    println!("总和: {}", sum);

    let product = nums.iter().fold(1, |acc, x| acc * x);
    println!("乘积: {}", product);

    let has_even = nums.iter().any(|&x| x % 2 == 0);
    println!("包含偶数: {}", has_even);

    for (idx, val) in "Rust".chars().enumerate() {
        println!("chars[{}]: {}", idx, val);
