    let first_three: Vec<i32> = nums.iter().take(3).cloned().collect();
    println!("前三个: {:?}", first_three);

    let skipped: Vec<i32> = nums.iter().skip(5).cloned().collect();
    println!("跳过前五个: {:?}", skipped);
}

