struct Counter {
    count: u32,
}

impl Counter {
    fn new() -> Counter {
        Counter { count: 0 }
    }
}

impl Iterator for Counter {
    type Item = u32;

    fn next(&mut self) -> Option<Self::Item> {
        if self.count < 5 {
            self.count += 1;
            Some(self.count)
        } else {
            None
        }
    }
}

use std::rc::Rc;
use std::cell::RefCell;

fn main() {
    // Box 在堆上分配
    let b = Box::new(5);
    println!("b = {}", b);

    // Rc 共享所有权
    let shared = Rc::new(RefCell::new(vec![1, 2, 3]));
    println!("引用计数: {}", Rc::strong_count(&shared));

    {
        let shared2 = Rc::clone(&shared);
        println!("clone 后引用计数: {}", Rc::strong_count(&shared));

        shared2.borrow_mut().push(4);
    }

    shared.borrow_mut().push(5);
    println!("共享数据: {:?}", shared.borrow());
    println!("最终引用计数: {}", Rc::strong_count(&shared));
}

use std::sync::{mpsc, Arc, Mutex};
use std::thread;
use std::time::Duration;

fn main() {
    // 消息传递
    let (tx, rx) = mpsc::channel();

    thread::spawn(move || {
        let vals = vec!["hi", "from", "the", "thread"];
        for val in vals {
            tx.send(val).unwrap();
            thread::sleep(Duration::from_millis(100));
        }
    });

    for received in rx {
        println!("收到: {}", received);
    }

    // 共享状态
    let counter = Arc::new(Mutex::new(0));
    let mut handles = vec![];

    for _ in 0..5 {
        let counter = Arc::clone(&counter);
        let handle = thread::spawn(move || {
            let mut num = counter.lock().unwrap();
            *num += 1;
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("计数器结果: {}", *counter.lock().unwrap());
}

